python3 << 'PYEOF'
import json
from datetime import datetime, timedelta, timezone, time as dtime
from zoneinfo import ZoneInfo
import re
import uuid

TZ = ZoneInfo("Asia/Shanghai")
UTC = timezone.utc

# ── Helpers ──────────────────────────────────────────────────────────────────
def parse_dt(s):
    return datetime.fromisoformat(s).astimezone(TZ)

def ics_utc(dt):
    return dt.astimezone(UTC).strftime("%Y%m%dT%H%M%SZ")

def parse_ics_dt(s):
    if s.endswith("Z"):
        dt = datetime.strptime(s, "%Y%m%dT%H%M%SZ").replace(tzinfo=UTC)
    else:
        dt = datetime.strptime(s, "%Y%m%dT%H%M%S").replace(tzinfo=TZ)
    return dt.astimezone(TZ)

# ── Parse calendar.ics ───────────────────────────────────────────────────────
with open("/tmp_workspace/calendar.ics") as f:
    raw_ics = f.read()

vevent_blocks = re.findall(r"BEGIN:VEVENT.*?END:VEVENT", raw_ics, re.DOTALL)

def parse_vevent(block):
    def field(name):
        m = re.search(rf"^{name}:(.*)", block, re.MULTILINE)
        return m.group(1).strip() if m else None
    dtstart = parse_ics_dt(field("DTSTART"))
    dtend   = parse_ics_dt(field("DTEND"))
    attendees = re.findall(r"^ATTENDEE:mailto:(.+)", block, re.MULTILINE)
    return {"uid": field("UID"), "dtstart": dtstart, "dtend": dtend,
            "summary": field("SUMMARY"), "attendees": attendees, "block": block}

orig_events = [parse_vevent(b) for b in vevent_blocks]

# ── Parse meeting_requests.json ───────────────────────────────────────────────
with open("/tmp_workspace/meeting_requests.json") as f:
    requests = json.load(f)

# ── Constraints ───────────────────────────────────────────────────────────────
LUNCH_START = dtime(12, 0)
LUNCH_END   = dtime(13, 0)
MAX_MEETINGS_PER_DAY = 4

ATTENDEE_UNAVAIL = {
    "alice@example.com": [("Wednesday", dtime(0,0), dtime(23,59))],
    "frank@example.com": [("Friday",    dtime(17,0), dtime(23,59))],
    "grace@example.com": [("Tuesday",   dtime(9,0),  dtime(10,0))],
}

PRIORITY_WEIGHT = {"P0": 5, "P1": 3, "P2": 1}
WEEKDAY_NAMES = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"]

# ── Build per-attendee meeting count from existing events ─────────────────────
# key: (attendee, date_str) -> list of (start, end)
attendee_schedule = {}  # (email, date_iso) -> [(start, end), ...]

def date_key(dt):
    return dt.date().isoformat()

for ev in orig_events:
    d = date_key(ev["dtstart"])
    for a in ev["attendees"]:
        attendee_schedule.setdefault((a, d), []).append((ev["dtstart"], ev["dtend"]))

def get_meetings_on_day(attendee, date_iso):
    return attendee_schedule.get((attendee, date_iso), [])

def meetings_count_on_day(attendee, date_iso):
    return len(get_meetings_on_day(attendee, date_iso))

def overlaps(s1, e1, s2, e2):
    """True if [s1,e1) overlaps [s2,e2)"""
    return s1 < e2 and e1 > s2

def conflicts_with_lunch(start, end):
    """True if the slot overlaps 12:00-13:00 local"""
    lunch_s = datetime.combine(start.date(), LUNCH_START, tzinfo=TZ)
    lunch_e = datetime.combine(start.date(), LUNCH_END,   tzinfo=TZ)
    return overlaps(start, end, lunch_s, lunch_e)

def is_attendee_unavailable(attendee, start, end):
    """Return reason string if attendee is unavailable, else None."""
    weekday_name = WEEKDAY_NAMES[start.weekday()]
    rules = ATTENDEE_UNAVAIL.get(attendee, [])
    for (wday, rs, re_t) in rules:
        if wday == weekday_name:
            rule_s = datetime.combine(start.date(), rs, tzinfo=TZ)
            rule_e = datetime.combine(start.date(), re_t, tzinfo=TZ)
            if overlaps(start, end, rule_s, rule_e):
                return f"{attendee} is unavailable on {wday} during this window"
    return None

def attendee_has_conflict(attendee, start, end, date_iso):
    """Check if attendee has an existing meeting overlapping [start,end)"""
    for (ms, me) in get_meetings_on_day(attendee, date_iso):
        if overlaps(start, end, ms, me):
            return True
    return False

def try_schedule(req, slot_start, slot_end, dur_min):
    """
    Try to place a meeting of dur_min minutes starting at slot_start.
    Returns (chosen_start, chosen_end, reason_code, reason_text) or None if impossible.
    """
    dur = timedelta(minutes=dur_min)
    # Earliest start is slot_start, latest end is slot_end
    t = slot_start
    while t + dur <= slot_end:
        end = t + dur
        date_iso = date_key(t)

        # Hard: no lunch overlap
        if conflicts_with_lunch(t, end):
            t = datetime.combine(t.date(), LUNCH_END, tzinfo=TZ)
            continue

        # Hard: attendee unavailability
        blocked = None
        for att in req["required_attendees"]:
            reason = is_attendee_unavailable(att, t, end)
            if reason:
                blocked = (att, reason, "attendee_unavailable")
                break
        if blocked:
            # Can't fix by shifting within same window usually – try next minute
            t += timedelta(minutes=1)
            continue

        # Hard: attendee time conflicts
        conflict_att = None
        for att in req["required_attendees"]:
            if attendee_has_conflict(att, t, end, date_iso):
                conflict_att = att
                break
        if conflict_att:
            t += timedelta(minutes=1)
            continue

        # Hard: daily meeting cap
        over_cap = None
        for att in req["required_attendees"]:
            if meetings_count_on_day(att, date_iso) >= MAX_MEETINGS_PER_DAY:
                over_cap = att
                break
        if over_cap:
            # No use shifting time on same day for this attendee
            return None, "daily_limit_exceeded", f"{over_cap} already has {MAX_MEETINGS_PER_DAY} meetings on {date_iso}"

        # All constraints pass
        return (t, end), None, None

        t += timedelta(minutes=1)

    return None, None, None

# ── Sort requests by priority (P0 first, then P1, then P2) ───────────────────
priority_order = {"P0": 0, "P1": 1, "P2": 2}
sorted_requests = sorted(requests, key=lambda r: priority_order[r["priority"]])

# ── Main scheduling loop ──────────────────────────────────────────────────────
scheduled = []    # list of dicts with scheduling info
unscheduled = []  # list of dicts for output

for req in sorted_requests:
    placed = False
    last_fail_code = "outside_preferred_window"
    last_fail_text = "No preferred window could accommodate the meeting."

    # Sort windows: for P0 prefer earlier (soft constraint)
    windows = req["preferred_windows"]
    if req["priority"] == "P0":
        windows = sorted(windows, key=lambda w: w["start"])

    for window in windows:
        ws = parse_dt(window["start"])
        we = parse_dt(window["end"])

        result, fail_code, fail_text = try_schedule(req, ws, we, req["duration_minutes"])

        if result:
            chosen_start, chosen_end = result
            date_iso = date_key(chosen_start)

            # Register the meeting for all required attendees
            for att in req["required_attendees"]:
                attendee_schedule.setdefault((att, date_iso), []).append((chosen_start, chosen_end))

            uid = f"new-{req['id']}@example.com"
            scheduled.append({
                "req": req,
                "uid": uid,
                "dtstart": chosen_start,
                "dtend": chosen_end,
                "date_iso": date_iso,
            })
            placed = True
            print(f"✅ SCHEDULED {req['id']} ({req['priority']}) '{req['title']}': "
                  f"{chosen_start.strftime('%Y-%m-%d %H:%M')} - {chosen_end.strftime('%H:%M')}")
            break
        elif fail_code:
            last_fail_code = fail_code
            last_fail_text = fail_text

    if not placed:
        # Determine best reason
        # Re-check each window to find the most informative reason
        best_code = "outside_preferred_window"
        best_text = f"No slot of {req['duration_minutes']} min fits within any preferred window after applying all constraints."

        for window in req["preferred_windows"]:
            ws = parse_dt(window["start"])
            we = parse_dt(window["end"])
            dur = timedelta(minutes=req["duration_minutes"])

            t = ws
            found_any_attendee_issue = None
            found_lunch = False
            found_conflict = False
            found_cap = False

            while t + dur <= we:
                end = t + dur
                date_iso = date_key(t)

                if conflicts_with_lunch(t, end):
                    found_lunch = True
                    t = datetime.combine(t.date(), LUNCH_END, tzinfo=TZ)
                    continue

                unavail_reason = None
                for att in req["required_attendees"]:
                    r = is_attendee_unavailable(att, t, end)
                    if r:
                        unavail_reason = r
                        found_any_attendee_issue = ("attendee_unavailable", r)
                        break
                if unavail_reason:
                    t += timedelta(minutes=1)
                    continue

                for att in req["required_attendees"]:
                    if attendee_has_conflict(att, t, end, date_iso):
                        found_conflict = True
                        found_any_attendee_issue = ("time_conflict", f"{att} has a conflicting meeting in this window")
                        break
                if found_conflict:
                    t += timedelta(minutes=1)
                    continue

                for att in req["required_attendees"]:
                    if meetings_count_on_day(att, date_iso) >= MAX_MEETINGS_PER_DAY:
                        found_cap = True
                        found_any_attendee_issue = ("daily_limit_exceeded", f"{att} already has 4 meetings on {date_iso}")
                        break
                if found_cap:
                    break

                t += timedelta(minutes=1)

            if found_any_attendee_issue:
                best_code, best_text = found_any_attendee_issue
                if best_code == "attendee_unavailable":
                    break  # definitive reason found

        unscheduled.append({
